  ('medical-tech-moex-01840', 'medical-tech', 'medical-tech-moex-114-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有  關缺鐵性貧血之致病機轉，下列敘述何者最不適當？', '["缺  鐵性貧血成人男性，通常是由於慢性出血造成", "缺  鐵性貧血嬰兒，常因營養攝取不足造成", "若  完全未攝食含鐵食物，大約3至4週內就會出現顯著紅血球指數變化", "長  期抑制胃酸分泌會造成腸道對鐵吸收不良"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:05+00:00", "source_pdf_sha1": "7b84322cc241", "answer_pdf_sha1": "79b65d4ed5cc", "source_family": "moex-gov-tw", "moex": {"exam_code": "114090", "c": "308", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "114", "exam_name": "114年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
